namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = "";
    public string Category { get; set; } = "";
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public string Description { get; set; } = "";
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Spaghetti Carbonara", Category = "Pasta",
            Description = "A classic Roman pasta dish with eggs, cheese, and pancetta.",
            Ingredients = ["400g spaghetti", "200g pancetta", "4 egg yolks", "100g Pecorino Romano", "Black pepper"],
            Steps = ["Cook spaghetti in salted boiling water.", "Fry pancetta until crisp.", "Whisk egg yolks with grated cheese and pepper.", "Toss hot pasta with pancetta, then stir in egg mixture off heat.", "Serve immediately with extra cheese."]
        },
        new()
        {
            Id = 2, Title = "Margherita Pizza", Category = "Pasta",
            Description = "Simple and delicious Neapolitan pizza with fresh ingredients.",
            Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil"],
            Steps = ["Preheat oven to 250°C.", "Stretch dough into a circle.", "Spread crushed tomatoes over dough.", "Add torn mozzarella pieces.", "Bake 10-12 minutes, top with basil and olive oil."]
        },
        new()
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Curries",
            Description = "Tender chicken in a creamy spiced tomato sauce.",
            Ingredients = ["500g chicken breast", "200ml yogurt", "400g canned tomatoes", "200ml cream", "Garam masala, cumin, turmeric"],
            Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or pan-fry chicken until charred.", "Simmer tomatoes with spices, then add cream.", "Add chicken to sauce and cook 10 minutes.", "Serve with basmati rice or naan."]
        },
        new()
        {
            Id = 4, Title = "Vegetable Thai Green Curry", Category = "Curries",
            Description = "Aromatic coconut curry loaded with fresh vegetables.",
            Ingredients = ["Green curry paste", "400ml coconut milk", "Mixed vegetables", "Thai basil", "Fish sauce, lime juice"],
            Steps = ["Fry curry paste in oil for 1 minute.", "Add coconut milk and bring to a simmer.", "Add vegetables and cook until tender.", "Season with fish sauce and lime juice.", "Garnish with Thai basil and serve with rice."]
        },
        new()
        {
            Id = 5, Title = "Classic Chocolate Cake", Category = "Desserts",
            Description = "Rich, moist chocolate cake with ganache frosting.",
            Ingredients = ["200g flour", "200g sugar", "75g cocoa powder", "2 eggs", "200ml buttermilk"],
            Steps = ["Preheat oven to 180°C and grease two 9-inch pans.", "Mix dry ingredients, then add eggs and buttermilk.", "Pour into pans and bake 25-30 minutes.", "Cool completely before frosting.", "Top with chocolate ganache."]
        },
        new()
        {
            Id = 6, Title = "Lemon Tart", Category = "Desserts",
            Description = "Tangy lemon curd in a buttery shortcrust pastry.",
            Ingredients = ["Shortcrust pastry", "4 lemons", "4 eggs", "200g sugar", "100g butter"],
            Steps = ["Blind bake the pastry shell at 180°C.", "Whisk lemon juice, zest, eggs, and sugar.", "Cook over low heat with butter until thickened.", "Pour filling into cooled pastry shell.", "Chill for 2 hours before serving."]
        },
        new()
        {
            Id = 7, Title = "Caesar Salad", Category = "Salads",
            Description = "Crisp romaine lettuce with creamy Caesar dressing and croutons.",
            Ingredients = ["Romaine lettuce", "Parmesan cheese", "Croutons", "Caesar dressing", "Anchovy fillets"],
            Steps = ["Wash and chop romaine lettuce.", "Make dressing with anchovy, garlic, lemon, and Parmesan.", "Toss lettuce with dressing.", "Top with croutons and shaved Parmesan.", "Serve immediately."]
        },
        new()
        {
            Id = 8, Title = "Greek Salad", Category = "Salads",
            Description = "Fresh Mediterranean salad with feta and olives.",
            Ingredients = ["Tomatoes", "Cucumber", "Red onion", "Feta cheese", "Kalamata olives"],
            Steps = ["Chop tomatoes, cucumber, and red onion.", "Combine vegetables in a bowl.", "Add olives and crumbled feta.", "Dress with olive oil, oregano, and red wine vinegar.", "Toss gently and serve."]
        }
    ];

    // Tracks ratings per recipe: RecipeId -> list of ratings
    private readonly Dictionary<int, List<int>> _ratings = [];

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        if (stars < 1 || stars > 5) return;
        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = [];
        _ratings[recipeId].Add(stars);
    }

    public (double Average, int Count) GetRating(int recipeId)
    {
        if (!_ratings.TryGetValue(recipeId, out var ratings) || ratings.Count == 0)
            return (0, 0);
        return (ratings.Average(), ratings.Count);
    }
}

