@page "/categories"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>All Categories</PageTitle>

<h1>Recipe Categories</h1>
<div class="row mt-3">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-4 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h4 class="card-title">@category</h4>
                    <p class="card-text text-muted">
                        @RecipeService.GetByCategory(category).Count recipe(s)
                    </p>
                    <a href="categories/@category" class="btn btn-outline-primary">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

@page "/categories/{CategoryName}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<h1>@CategoryName Recipes</h1>
<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="categories">Categories</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (Recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row mt-3">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = "";

    private List<RecipeShare.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@inject RecipeShare.Services.RecipeService RecipeService

@if (Recipe is null)
{
    <PageTitle>Recipe Not Found</PageTitle>
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <PageTitle>@Recipe.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="categories">Categories</a></li>
            <li class="breadcrumb-item"><a href="categories/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h1>@Recipe.Title</h1>
    <p class="lead">@Recipe.Description</p>

    <StarRating RecipeId="Recipe.Id" @rendermode="InteractiveServer" />

    <h3 class="mt-4">Ingredients</h3>
    <ul class="list-group list-group-flush mb-4">
        @foreach (var ingredient in Recipe.Ingredients)
        {
            <li class="list-group-item">@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol class="list-group list-group-numbered mb-4">
        @foreach (var step in Recipe.Steps)
        {
            <li class="list-group-item">@step</li>
        }
    </ol>
}

@code {
    [Parameter] public int Id { get; set; }

    private RecipeShare.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@inject RecipeShare.Services.RecipeService RecipeService

<div class="my-3">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= DisplayStars ? "filled" : "")"
              @onclick="() => Rate(star)"
              @onmouseover="() => HoverStars = star"
              @onmouseout="() => HoverStars = 0"
              role="button"
              title="@star star(s)">★</span>
    }
    @if (RatingCount > 0)
    {
        <span class="ms-3 text-muted">
            @AverageRating.ToString("0.0") avg · @RatingCount rating(s)
        </span>
    }
    @if (JustRated)
    {
        <span class="ms-2 text-success">✓ Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int HoverStars { get; set; }
    private int SelectedStars { get; set; }
    private double AverageRating { get; set; }
    private int RatingCount { get; set; }
    private bool JustRated { get; set; }

    private int DisplayStars => HoverStars > 0 ? HoverStars : SelectedStars;

    protected override void OnParametersSet() => LoadRating();

    private void Rate(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        SelectedStars = stars;
        JustRated = true;
        LoadRating();
    }

    private void LoadRating()
    {
        var (avg, count) = RecipeService.GetRating(RecipeId);
        AverageRating = avg;
        RatingCount = count;
    }
}

.star {
    font-size: 1.6rem;
    color: #ccc;
    cursor: pointer;
    transition: color 0.15s;
    user-select: none;
}

.star:hover,
.star.filled {
    color: #f5a623;
}

@page "/submit"
@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community.</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe has been added.
        <a href="recipe/@NewRecipeId">View it here</a>.
    </div>
}

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Title</label>
        <InputText id="title" class="form-control" @bind-Value="Model.Title" />
        <ValidationMessage For="() => Model.Title" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputText id="category" class="form-control" @bind-Value="Model.Category"
                   placeholder="e.g. Pasta, Curries, Desserts, Salads" />
        <ValidationMessage For="() => Model.Category" />
    </div>

    <div class="mb-3">
        <label for="description" class="form-label">Description</label>
        <InputTextArea id="description" class="form-control" rows="2" @bind-Value="Model.Description" />
        <ValidationMessage For="() => Model.Description" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="Model.IngredientsText" />
        <ValidationMessage For="() => Model.IngredientsText" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="Model.StepsText" />
        <ValidationMessage For="() => Model.StepsText" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    private SubmitRecipeModel Model { get; set; } = new();
    private bool Submitted { get; set; }
    private int NewRecipeId { get; set; }

    private void HandleSubmit()
    {
        var recipe = new RecipeShare.Models.Recipe
        {
            Title = Model.Title,
            Category = Model.Category,
            Description = Model.Description,
            Ingredients = Model.IngredientsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = Model.StepsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };

        RecipeService.AddRecipe(recipe);
        NewRecipeId = recipe.Id;
        Submitted = true;
        Model = new();
    }

    private class SubmitRecipeModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required.")]
        public string Category { get; set; } = "";

        public string Description { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Add at least one ingredient.")]
        public string IngredientsText { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Add at least one step.")]
        public string StepsText { get; set; } = "";
    }
}

